## 二、核心代码实现

### 2.1 插件入口 (src/index.ts)

```typescript
import type { OpenClawPluginApi } from "openclaw/plugin-sdk";
import { practiceRouter } from "./api/practice.js";
import { userRouter } from "./api/user.js";
import { contentRouter } from "./api/content.js";
import { analyticsRouter } from "./api/analytics.js";
import { PracticeService } from "./services/PracticeService.js";
import { ContentService } from "./services/ContentService.js";
import { AnalyticsService } from "./services/AnalyticsService.js";
import { registerPracticeTool } from "./tools/zhiguan_practice.js";
import { registerStatsTool } from "./tools/zhiguan_stats.js";
import { registerContentTool } from "./tools/zhiguan_content.js";
import { setupDatabase } from "./database/setup.js";

export interface ZhiguanConfig {
  database?: {
    type: "sqlite" | "postgres";
    connection?: string;
  };
  content?: {
    path?: string;
    cdnUrl?: string;
  };
  features?: {
    wearable?: boolean;
    eeg?: boolean;
    vr?: boolean;
    analytics?: boolean;
  };
  api?: {
    rateLimit?: number;
    cors?: boolean;
  };
}

// 插件全局状态
export interface ZhiguanContext {
  config: ZhiguanConfig;
  services: {
    practice: PracticeService;
    content: ContentService;
    analytics: AnalyticsService;
  };
}

let zhiguanContext: ZhiguanContext | null = null;

export function getZhiguanContext(): ZhiguanContext {
  if (!zhiguanContext) {
    throw new Error("Zhiguan plugin not initialized");
  }
  return zhiguanContext;
}

const plugin = {
  id: "zhiguan",
  name: "止观AI",
  description: "传统止观禅修数字化系统",

  async register(api: OpenClawPluginApi) {
    const config = api.config.plugins?.entries?.zhiguan?.config as ZhiguanConfig || {};

    // 1. 初始化数据库
    const db = await setupDatabase(config.database);

    // 2. 初始化服务
    const services = {
      practice: new PracticeService(db),
      content: new ContentService(config.content),
      analytics: new AnalyticsService(db),
    };

    zhiguanContext = { config, services };

    // 3. 注册API路由
    api.registerGatewayMethod("zhiguan.practice.start", practiceRouter.start);
    api.registerGatewayMethod("zhiguan.practice.end", practiceRouter.end);
    api.registerGatewayMethod("zhiguan.practice.get", practiceRouter.get);
    api.registerGatewayMethod("zhiguan.user.stats", userRouter.stats);
    api.registerGatewayMethod("zhiguan.user.profile", userRouter.profile);
    api.registerGatewayMethod("zhiguan.content.get", contentRouter.get);
    api.registerGatewayMethod("zhiguan.content.list", contentRouter.list);
    api.registerGatewayMethod("zhiguan.analytics.report", analyticsRouter.report);

    // 4. 注册Agent工具
    registerPracticeTool(api);
    registerStatsTool(api);
    registerContentTool(api);

    // 5. 注册CLI命令
    api.registerCli(
      ({ program }) => {
        const zhiguanCmd = program.command("zhiguan")
          .description("止观AI管理命令");

        zhiguanCmd.command("status")
          .description("查看止观系统状态")
          .action(async () => {
            console.log("止观AI系统状态:");
            console.log(`- 数据库: ${config.database?.type || "sqlite"}`);
            console.log(`- 内容路径: ${config.content?.path || "./content"}`);
            console.log(`- 可穿戴: ${config.features?.wearable ? "启用" : "禁用"}`);
            console.log(`- 脑电: ${config.features?.eeg ? "启用" : "禁用"}`);
            console.log(`- VR: ${config.features?.vr ? "启用" : "禁用"}`);
          });

        zhiguanCmd.command("import-content")
          .description("导入止观内容")
          .argument("<path>", "内容目录路径")
          .action(async (path) => {
            await services.content.importFromDirectory(path);
            console.log("内容导入完成");
          });

        zhiguanCmd.command("export-data")
          .description("导出用户数据（匿名化）")
          .option("-o, --output <path>", "输出路径")
          .action(async (options) => {
            await services.analytics.exportAnonymousData(options.output);
            console.log("数据导出完成");
          });
      },
      { commands: ["zhiguan"] }
    );

    // 6. 注册Slash命令（用户可直接使用）
    api.registerCommand({
      name: "zhiguan",
      description: "开始一次3分钟止观练习",
      handler: async (ctx) => {
        return {
          text: "🧘 止观练习\n\n请打开止观AI应用开始练习。\n\n今日修行要点：数息时，知道自己在数息；心跑掉了，拉回来就好。",
        };
      },
    });

    api.registerCommand({
      name: "zhiguan-stats",
      description: "查看修行统计",
      handler: async (ctx) => {
        // 这里可以获取用户的实际统计
        return {
          text: "📊 本周修行统计\n\n练习次数：5次\n总时长：15分钟\n连续天数：3天\n\n继续精进！",
        };
      },
    });

    // 7. 启动后台服务（如果有）
    if (config.features?.wearable) {
      api.registerService({
        id: "zhiguan-wearable",
        start: () => {
          api.logger.info("止观可穿戴设备服务启动");
          // 初始化蓝牙扫描等
        },
        stop: () => {
          api.logger.info("止观可穿戴设备服务停止");
        },
      });
    }

    api.logger.info("止观AI插件加载完成");
  },
};

export default plugin;
