### 2.2 练习服务 (src/services/PracticeService.ts)

```typescript
import type { Database } from "../database/setup.js";

export interface PracticeSession {
  id: string;
  userId: string;
  startTime: Date;
  endTime?: Date;
  duration: number; // 计划时长（分钟）
  actualDuration?: number; // 实际时长（秒）
  mode: "guided" | "silent";
  context: "commute" | "work" | "home" | "walking" | "other";
  status: "active" | "completed" | "interrupted";
  feedback?: {
    quality: 1 | 2 | 3 | 4 | 5;
    notes?: string;
  };
  // 生理数据（可选）
  physiological?: {
    heartRateAvg?: number;
    heartRateVariability?: number;
    breathRate?: number;
  };
}

export class PracticeService {
  constructor(private db: Database) {}

  async startSession(params: {
    userId: string;
    duration: 3 | 5 | 10 | 15 | 25;
    mode: "guided" | "silent";
    context: string;
  }): Promise<PracticeSession> {
    const session: PracticeSession = {
      id: this.generateId(),
      userId: params.userId,
      startTime: new Date(),
      duration: params.duration,
      mode: params.mode,
      context: params.context as any,
      status: "active",
    };

    await this.db.practice.create({
      data: {
        id: session.id,
        userId: session.userId,
        startTime: session.startTime,
        duration: session.duration,
        mode: session.mode,
        context: session.context,
        status: session.status,
      },
    });

    return session;
  }

  async endSession(
    sessionId: string,
    feedback?: { quality: 1 | 2 | 3 | 4 | 5; notes?: string }
  ): Promise<PracticeSession> {
    const session = await this.db.practice.findUnique({
      where: { id: sessionId },
    });

    if (!session) {
      throw new Error("Session not found");
    }

    const endTime = new Date();
    const actualDuration = Math.floor(
      (endTime.getTime() - session.startTime.getTime()) / 1000
    );

    const updated = await this.db.practice.update({
      where: { id: sessionId },
      data: {
        endTime,
        actualDuration,
        status: "completed",
        feedbackQuality: feedback?.quality,
        feedbackNotes: feedback?.notes,
      },
    });

    return updated as PracticeSession;
  }

  async getUserStats(userId: string, period: "week" | "month" | "year") {
    const now = new Date();
    const startDate = new Date();

    switch (period) {
      case "week":
        startDate.setDate(now.getDate() - 7);
        break;
      case "month":
        startDate.setMonth(now.getMonth() - 1);
        break;
      case "year":
        startDate.setFullYear(now.getFullYear() - 1);
        break;
    }

    const practices = await this.db.practice.findMany({
      where: {
        userId,
        startTime: { gte: startDate },
        status: "completed",
      },
    });

    const totalSessions = practices.length;
    const totalDuration = practices.reduce(
      (sum, p) => sum + (p.actualDuration || 0),
      0
    );
    const averageQuality =
      practices.reduce((sum, p) => sum + (p.feedbackQuality || 0), 0) /
      totalSessions || 0;

    // 计算连续天数
    const streak = this.calculateStreak(practices);

    return {
      period,
      totalSessions,
      totalDuration,
      averageQuality: Math.round(averageQuality * 10) / 10,
      streak,
      practices: practices.map((p) => ({
        id: p.id,
        date: p.startTime,
        duration: p.actualDuration,
        quality: p.feedbackQuality,
      })),
    };
  }

  private calculateStreak(practices: any[]): number {
    if (practices.length === 0) return 0;

    const dates = practices
      .map((p) => new Date(p.startTime).toDateString())
      .filter((v, i, a) => a.indexOf(v) === i) // 去重
      .sort((a, b) => new Date(b).getTime() - new Date(a).getTime());

    let streak = 0;
    const today = new Date().toDateString();
    const yesterday = new Date(Date.now() - 86400000).toDateString();

    // 检查今天或昨天是否有练习
    if (dates[0] === today || dates[0] === yesterday) {
      streak = 1;
      for (let i = 1; i < dates.length; i++) {
        const prevDate = new Date(dates[i - 1]);
        const currDate = new Date(dates[i]);
        const diffDays = Math.floor(
          (prevDate.getTime() - currDate.getTime()) / 86400000
        );
        if (diffDays === 1) {
          streak++;
        } else {
          break;
        }
      }
    }

    return streak;
  }

  private generateId(): string {
    return `zg_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }
}
