### 2.3 Agent工具 (src/tools/zhiguan_practice.ts)

```typescript
import type { OpenClawPluginApi } from "openclaw/plugin-sdk";
import { Type } from "@sinclair/typebox";
import { getZhiguanContext } from "../index.js";

export function registerPracticeTool(api: OpenClawPluginApi) {
  // 开始练习工具
  api.registerTool(
    {
      name: "zhiguan_start_practice",
      description: "为用户开始一次止观练习会话",
      parameters: Type.Object({
        userId: Type.String({ description: "用户ID" }),
        duration: Type.Number({
          description: "练习时长（分钟）",
          enum: [3, 5, 10, 15, 25],
        }),
        mode: Type.String({
          description: "练习模式",
          enum: ["guided", "silent"],
        }),
        context: Type.String({
          description: "练习场景",
          enum: ["commute", "work", "home", "walking", "other"],
        }),
      }),
      async execute(_id, params) {
        const { services } = getZhiguanContext();

        const session = await services.practice.startSession({
          userId: params.userId,
          duration: params.duration as 3 | 5 | 10 | 15 | 25,
          mode: params.mode as "guided" | "silent",
          context: params.context,
        });

        return {
          content: [
            {
              type: "text",
              text: `止观练习已开始\n\n会话ID: ${session.id}\n时长: ${session.duration}分钟\n模式: ${session.mode === "guided" ? "引导" : "自主"}\n场景: ${session.context}\n\n请引导用户开始调身、调息、观心。`,
            },
          ],
        };
      },
    },
    { optional: true }
  );

  // 结束练习工具
  api.registerTool(
    {
      name: "zhiguan_end_practice",
      description: "结束用户的止观练习会话",
      parameters: Type.Object({
        sessionId: Type.String({ description: "练习会话ID" }),
        quality: Type.Number({
          description: "练习质量评分（1-5）",
          minimum: 1,
          maximum: 5,
        }),
        notes: Type.Optional(Type.String({ description: "用户反馈备注" })),
      }),
      async execute(_id, params) {
        const { services } = getZhiguanContext();

        const session = await services.practice.endSession(params.sessionId, {
          quality: params.quality as 1 | 2 | 3 | 4 | 5,
          notes: params.notes,
        });

        return {
          content: [
            {
              type: "text",
              text: `练习已完成\n\n实际时长: ${session.actualDuration}秒\n质量评分: ${session.feedback?.quality}/5\n\n今日修行要点：心跑掉了没关系，发现的那一刻就是观的开始。`,
            },
          ],
        };
      },
    },
    { optional: true }
  );

  // 获取练习统计工具
  api.registerTool(
    {
      name: "zhiguan_get_stats",
      description: "获取用户的止观练习统计数据",
      parameters: Type.Object({
        userId: Type.String({ description: "用户ID" }),
        period: Type.String({
          description: "统计周期",
          enum: ["week", "month", "year"],
        }),
      }),
      async execute(_id, params) {
        const { services } = getZhiguanContext();

        const stats = await services.practice.getUserStats(
          params.userId,
          params.period as "week" | "month" | "year"
        );

        return {
          content: [
            {
              type: "text",
              text: `📊 ${params.period === "week" ? "本周" : params.period === "month" ? "本月" : "本年"}修行统计\n\n练习次数: ${stats.totalSessions}次\n总时长: ${Math.floor(stats.totalDuration / 60)}分钟\n平均质量: ${stats.averageQuality}/5\n连续天数: ${stats.streak}天\n\n${stats.streak >= 7 ? "🎉 已坚持一周，可以开始尝试无引导模式了！" : "继续精进！"}`,
            },
          ],
        };
      },
    },
    { optional: true }
  );
}
