### 2.4 API路由 (src/api/practice.ts)

```typescript
import { getZhiguanContext } from "../index.js";

export const practiceRouter = {
  // 开始练习
  async start({ request, respond }: any) {
    const { userId, duration, mode, context } = request.params;
    const { services } = getZhiguanContext();

    try {
      const session = await services.practice.startSession({
        userId,
        duration,
        mode,
        context,
      });

      respond(true, {
        sessionId: session.id,
        startTime: session.startTime,
        duration: session.duration,
        mode: session.mode,
      });
    } catch (error) {
      respond(false, { error: (error as Error).message });
    }
  },

  // 结束练习
  async end({ request, respond }: any) {
    const { sessionId, feedback } = request.params;
    const { services } = getZhiguanContext();

    try {
      const session = await services.practice.endSession(sessionId, feedback);

      respond(true, {
        sessionId: session.id,
        actualDuration: session.actualDuration,
        status: session.status,
      });
    } catch (error) {
      respond(false, { error: (error as Error).message });
    }
  },

  // 获取练习记录
  async get({ request, respond }: any) {
    const { sessionId } = request.params;
    const { services } = getZhiguanContext();

    // 实现获取单个练习记录
    respond(true, { sessionId });
  },
};
