App({
  globalData: {
    userInfo: null,
    practiceHistory: [],
    settings: {
      defaultDuration: 3,
      defaultMode: 'guided',
      soundEnabled: true,
      vibrationEnabled: true
    }
  },

  onLaunch() {
    // 加载本地存储的设置
    const settings = wx.getStorageSync('zhiguan_settings');
    if (settings) {
      this.globalData.settings = { ...this.globalData.settings, ...settings };
    }

    // 加载练习历史
    const history = wx.getStorageSync('zhiguan_history');
    if (history) {
      this.globalData.practiceHistory = history;
    }

    console.log('止观AI小程序启动');
  },

  // 保存练习记录
  savePractice(record) {
    this.globalData.practiceHistory.unshift(record);
    wx.setStorageSync('zhiguan_history', this.globalData.practiceHistory);
  },

  // 获取本周练习次数
  getWeeklyCount() {
    const now = new Date();
    const weekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
    return this.globalData.practiceHistory.filter(r => 
      new Date(r.date) > weekAgo
    ).length;
  },

  // 获取连续练习天数
  getStreak() {
    const history = this.globalData.practiceHistory;
    if (history.length === 0) return 0;

    const dates = [...new Set(history.map(r => 
      new Date(r.date).toDateString()
    ))].sort((a, b) => new Date(b) - new Date(a));

    let streak = 0;
    const today = new Date().toDateString();
    const yesterday = new Date(Date.now() - 86400000).toDateString();

    if (dates[0] === today || dates[0] === yesterday) {
      streak = 1;
      for (let i = 1; i < dates.length; i++) {
        const prev = new Date(dates[i - 1]);
        const curr = new Date(dates[i]);
        if ((prev - curr) / 86400000 === 1) {
          streak++;
        } else {
          break;
        }
      }
    }

    return streak;
  }
});

