// pages/index/index.js
const app = getApp();

Page({
  data: {
    greeting: '',
    todayCount: 0,
    streak: 0,
    totalMinutes: 0,
    selectedDuration: 3,
    selectedMode: 'guided',
    isReady: true
  },

  onLoad() {
    this.setGreeting();
    this.loadStats();
  },

  onShow() {
    this.loadStats();
  },

  // 设置问候语
  setGreeting() {
    const hour = new Date().getHours();
    let greeting = '你好';
    if (hour < 6) greeting = '夜深了';
    else if (hour < 9) greeting = '早安';
    else if (hour < 12) greeting = '上午好';
    else if (hour < 14) greeting = '午安';
    else if (hour < 18) greeting = '下午好';
    else greeting = '晚上好';

    this.setData({ greeting });
  },

  // 加载统计数据
  loadStats() {
    const history = app.globalData.practiceHistory;
    const today = new Date().toDateString();

    // 今日练习次数
    const todayCount = history.filter(r => 
      new Date(r.date).toDateString() === today
    ).length;

    // 连续天数
    const streak = app.getStreak();

    // 总分钟数
    const totalMinutes = Math.floor(
      history.reduce((sum, r) => sum + (r.duration || 0), 0) / 60
    );

    this.setData({
      todayCount,
      streak,
      totalMinutes
    });
  },

  // 选择时长
  selectDuration(e) {
    const duration = parseInt(e.currentTarget.dataset.duration);
    this.setData({ selectedDuration: duration });
  },

  // 选择模式
  selectMode(e) {
    const mode = e.currentTarget.dataset.mode;
    this.setData({ selectedMode: mode });
  },

  // 开始练习
  startPractice() {
    const { selectedDuration, selectedMode } = this.data;

    wx.navigateTo({
      url: `/pages/practice/practice?duration=${selectedDuration}&mode=${selectedMode}`
    });
  }
});

