```html
<script>
(function() {
    'use strict';

    var config = { duration: 3, mode: 'guided' };
    var timer = null;
    var timeLeft = 180;
    var totalTime = 180;
    var startTime = null;
    var rating = 0;
    var history = JSON.parse(localStorage.getItem('zhiguan_history') || '[]');

    var pages = {
        home: document.getElementById('home'),
        practice: document.getElementById('practice'),
        done: document.getElementById('done'),
        stats: document.getElementById('stats')
    };

    function setGreeting() {
        var hour = new Date().getHours();
        var text = '你好';
        if (hour < 6) text = '夜深了';
        else if (hour < 9) text = '早安';
        else if (hour < 12) text = '上午好';
        else if (hour < 14) text = '午安';
        else if (hour < 18) text = '下午好';
        else text = '晚上好';
        document.getElementById('greeting').textContent = text;
    }

    function formatTime(seconds) {
        var m = Math.floor(seconds / 60);
        var s = seconds % 60;
        return (m < 10 ? '0' : '') + m + ':' + (s < 10 ? '0' : '') + s;
    }

    function showPage(name) {
        Object.keys(pages).forEach(function(key) {
            pages[key].classList.remove('active');
        });
        pages[name].classList.add('active');

        document.querySelectorAll('.tab').forEach(function(tab) {
            tab.classList.remove('active');
            if (tab.dataset.page === name) tab.classList.add('active');
        });

        if (name === 'stats') renderHistory();
    }

    function updateBtnText() {
        var modeText = config.mode === 'guided' ? '引导' : '自主';
        document.getElementById('btnText').textContent = config.duration + '分钟 · ' + modeText;
    }

    document.querySelectorAll('[data-duration]').forEach(function(el) {
        el.addEventListener('click', function() {
            config.duration = parseInt(this.dataset.duration);
            document.querySelectorAll('[data-duration]').forEach(function(e) { e.classList.remove('active'); });
            this.classList.add('active');
            updateBtnText();
        });
    });

    document.querySelectorAll('[data-mode]').forEach(function(el) {
        el.addEventListener('click', function() {
            config.mode = this.dataset.mode;
            document.querySelectorAll('[data-mode]').forEach(function(e) { e.classList.remove('active'); });
            this.classList.add('active');
            updateBtnText();
        });
    });

    document.querySelectorAll('[data-page]').forEach(function(el) {
        el.addEventListener('click', function() { showPage(this.dataset.page); });
    });

    document.getElementById('startBtn').addEventListener('click', function() {
        timeLeft = config.duration * 60;
        totalTime = timeLeft;
        document.getElementById('timer').textContent = formatTime(timeLeft);
        document.getElementById('guide').style.display = config.mode === 'guided' ? 'block' : 'none';
        document.getElementById('controls').innerHTML = '<button class="btn btn-start" id="beginBtn">开始练习</button>';
        bindBeginBtn();
        showPage('practice');
    });

    function bindBeginBtn() {
        var btn = document.getElementById('beginBtn');
        if (btn) btn.addEventListener('click', beginPractice);
    }

    function beginPractice() {
        startTime = new Date();
        document.getElementById('controls').innerHTML = 
            '<button class="btn btn-pause" id="pauseBtn">暂停</button>' +
            '<button class="btn btn-end" id="endBtn">结束</button>';

        document.getElementById('pauseBtn').addEventListener('click', pausePractice);
        document.getElementById('endBtn').addEventListener('click', endPractice);

        timer = setInterval(function() {
            timeLeft--;
            document.getElementById('timer').textContent = formatTime(timeLeft);
            var progress = ((totalTime - timeLeft) / totalTime) * 100;
            document.getElementById('progressBar').style.width = progress + '%';
            updateStage();
            if (timeLeft <= 0) endPractice();
        }, 1000);
    }

    function pausePractice() {
        clearInterval(timer);
        document.getElementById('controls').innerHTML = 
            '<button class="btn btn-start" id="resumeBtn">继续</button>' +
            '<button class="btn btn-end" id="endBtn">结束</button>';
        document.getElementById('resumeBtn').addEventListener('click', beginPractice);
        document.getElementById('endBtn').addEventListener('click', endPractice);
    }

    function updateStage() {
        var elapsed = totalTime - timeLeft;
        var progress = elapsed / totalTime;
        var stage = '准备开始';
        var guide = '';

        if (progress > 0) {
            if (progress < 0.17) { stage = '调身'; guide = '让身体自然放松，脊柱轻轻挺直'; }
            else if (progress < 0.67) { stage = '调息'; guide = '吸气...呼气...保持自然的呼吸节奏'; }
            else if (progress < 0.89) { stage = '观心'; guide = '觉察身体的感觉，不评判，只是知道'; }
            else { stage = '收功'; guide = '慢慢把觉知带回，准备结束练习'; }
        }

        document.getElementById('stage').textContent = stage;
        if (config.mode === 'guided') document.getElementById('guide').textContent = guide;
    }

    function endPractice() {
        clearInterval(timer);
        var actual = Math.floor((new Date() - startTime) / 60000);
        if (actual < 1) actual = 1;
        document.getElementById('doneTime').textContent = '实际练习 ' + actual + ' 分钟';
        showPage('done');
    }

    document.getElementById('backBtn').addEventListener('click', function() {
        if (confirm('确定要退出练习吗？')) { clearInterval(timer); showPage('home'); }
    });

    document.querySelectorAll('[data-rating]').forEach(function(el) {
        el.addEventListener('click', function() {
            rating = parseInt(this.dataset.rating);
            document.querySelectorAll('[data-rating]').forEach(function(star, i) {
                star.classList.toggle('active', i < rating);
            });
        });
    });

    document.getElementById('saveBtn').addEventListener('click', function() {
        var record = {
            id: Date.now(),
            date: new Date().toISOString(),
            duration: config.duration,
            mode: config.mode,
            rating: rating,
            notes: document.getElementById('noteInput').value
        };
        history.unshift(record);
        localStorage.setItem('zhiguan_history', JSON.stringify(history));
        rating = 0;
        document.getElementById('noteInput').value = '';
        document.querySelectorAll('[data-rating]').forEach(function(s) { s.classList.remove('active'); });
        showPage('stats');
    });

    function renderHistory() {
        var container = document.getElementById('historyList');
        if (history.length === 0) {
            container.innerHTML = '<div class="empty">还没有练习记录<br><br>开始你的第一次止观练习吧 🧘</div>';
            return;
        }
        container.innerHTML = history.slice(0, 20).map(function(r) {
            var d = new Date(r.date);
            var stars = '★'.repeat(r.rating) + '☆'.repeat(5 - r.rating);
            return '<div class="history-item">' +
                '<div style="display:flex;justify-content:space-between;align-items:center">' +
                '<div><div style="font-size:18px;margin-bottom:4px">' + r.duration + '分钟止观</div>' +
                '<div style="font-size:12px;color:rgba(255,255,255,0.5)">' + (d.getMonth() + 1) + '月' + d.getDate() + '日 · ' + (r.mode === 'guided' ? '引导' : '自主') + '</div></div>' +
                '<div style="color:#ffc107;font-size:20px">' + stars + '</div></div>' +
                (r.notes ? '<div style="margin-top:10px;font-size:14px;color:rgba(255,255,255,0.7)">' + r.notes + '</div>' : '') +
                '</div>';
        }).join('');
    }

    setGreeting();
    bindBeginBtn();
})();
</script>
</body>
</html>
