        .timer { font-size: 64px; font-weight: 200; text-align: center; margin: 40px 0 20px; letter-spacing: 4px; font-family: monospace; }
        .stage { text-align: center; font-size: 18px; color: rgba(255,255,255,0.5); margin-bottom: 20px; }
