        .progress { width: 100%; max-width: 320px; margin: 0 auto 30px; height: 4px; background: rgba(255,255,255,0.1); border-radius: 2px; overflow: hidden; }
        .progress-bar { height: 100%; background: linear-gradient(90deg, #4a9eff, #357abd); width: 0%; transition: width 0.5s linear; }

        .controls { display: flex; justify-content: center; gap: 20px; margin-top: 30px; }
        .btn { padding: 15px 40px; border-radius: 25px; border: none; font-size: 16px; cursor: pointer; touch-action: manipulation; }
        .btn:active { transform: scale(0.95); }
        .btn-start { background: linear-gradient(135deg, #4a9eff 0%, #357abd 100%); color: #fff; }
        .btn-pause { background: #ffc107; color: #000; }
        .btn-end { background: #f44336; color: #fff; }
        .btn-save { background: linear-gradient(135deg, #4caf50 0%, #388e3c 100%); color: #fff; margin-top: 20px; }

        .stars { display: flex; justify-content: center; gap: 15px; margin: 30px 0; }
        .star { font-size: 40px; color: rgba(255,255,255,0.2); cursor: pointer; touch-action: manipulation; }
        .star.active { color: #ffc107; }

        .notes { width: 100%; max-width: 320px; height: 100px; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); border-radius: 12px; padding: 15px; color: #fff; margin: 20px auto; display: block; font-size: 16px; }
        .notes::placeholder { color: rgba(255,255,255,0.3); }

        .bottom-nav { 
            position: fixed; bottom: 0; left: 0; right: 0;
            background: rgba(26, 26, 46, 0.95); backdrop-filter: blur(10px);
            border-top: 1px solid rgba(255,255,255,0.1);
            padding: 10px 20px 20px;
            z-index: 1000;
        }
        .nav-inner { max-width: 440px; margin: 0 auto; display: flex; justify-content: space-around; background: rgba(255,255,255,0.05); border-radius: 16px; padding: 10px; }
        .nav-tab { text-align: center; cursor: pointer; padding: 12px 50px; border-radius: 12px; touch-action: manipulation; font-size: 16px; }
        .nav-tab.active { background: rgba(74,158,255,0.2); }

        .history-item { background: rgba(255,255,255,0.05); border-radius: 12px; padding: 15px; margin-bottom: 10px; }
        .back { color: rgba(255,255,255,0.6); cursor: pointer; margin-bottom: 20px; display: inline-block; padding: 10px; touch-action: manipulation; }

        .done-page { text-align: center; padding-top: 60px; }
        .done-title { font-size: 32px; margin-bottom: 15px; }
        .done-time { font-size: 16px; color: rgba(255,255,255,0.6); margin-bottom: 40px; }
        .empty { text-align: center; padding: 60px 20px; color: rgba(255,255,255,0.5); }
    </style>
</head>
<body>
    <div class="app">
        <div class="content">
            <!-- 首页 -->
            <div id="home" class="page active">
                <div class="header">
                    <div class="greeting" id="greeting">你好</div>
                    <div class="subtitle">每日止观，回归当下</div>
                </div>

                <button class="main-btn" id="startBtn">
                    <span class="main-btn-text">开始止观</span>
                    <span class="main-btn-sub" id="btnText">3分钟 · 引导</span>
                </button>

                <div class="selector">
                    <span class="selector-label">选择时长</span>
                    <div class="options">
                        <div class="option active" data-duration="3"><span class="option-num">3</span><span class="option-unit">分钟</span></div>
                        <div class="option" data-duration="5"><span class="option-num">5</span><span class="option-unit">分钟</span></div>
                        <div class="option" data-duration="10"><span class="option-num">10</span><span class="option-unit">分钟</span></div>
                    </div>
                </div>

                <div class="selector">
                    <span class="selector-label">练习模式</span>
                    <div class="options">
                        <div class="option active" data-mode="guided"><span class="option-num">引导</span><span class="option-unit">适合初学</span></div>
                        <div class="option" data-mode="silent"><span class="option-num">自主</span><span class="option-unit">适合熟练</span></div>
                    </div>
                </div>
            </div>

            <!-- 练习页 -->
            <div id="practice" class="page">
                <span class="back" id="backBtn">← 返回</span>
                <div class="timer" id="timer">03:00</div>
                <div class="stage" id="stage">准备开始</div>
                <div class="guide" id="guide" style="display:none">让身体自然放松</div>
                <div class="progress"><div class="progress-bar" id="progressBar"></div></div>
                <div class="controls" id="controls">
                    <button class="btn btn-start" id="beginBtn">开始练习</button>
                </div>
            </div>

            <!-- 完成页 -->
            <div id="done" class="page done-page">
                <div class="done-title">🎉 练习完成</div>
                <div class="done-time" id="doneTime">实际练习 3 分钟</div>
                <div class="stars" id="starContainer">
                    <span class="star" data-rating="1">★</span>
                    <span class="star" data-rating="2">★</span>
                    <span class="star" data-rating="3">★</span>
                    <span class="star" data-rating="4">★</span>
                    <span class="star" data-rating="5">★</span>
                </div>
                <textarea class="notes" id="noteInput" placeholder="记录这次练习的感受（可选）"></textarea>
                <button class="btn btn-save" id="saveBtn">保存记录</button>
            </div>

            <!-- 统计页 -->
            <div id="stats" class="page">
                <div class="header">
                    <div class="greeting">修行记录</div>
                </div>
                <div id="historyList"></div>
            </div>
        </div>

        <!-- 底部导航 -->
        <div class="bottom-nav">
            <div class="nav-inner">
                <div class="nav-tab active" data-page="home">练习</div>
                <div class="nav-tab" data-page="stats">记录</div>
            </div>
        </div>
    </div>

<script>
(function() {
    'use strict';

    var config = { duration: 3, mode: 'guided' };
    var timer = null;
    var timeLeft = 180;
    var totalTime = 180;
    var startTime = null;
    var rating = 0;
    var history = JSON.parse(localStorage.getItem('zhiguan_history') || '[]');

    var pages = {
        home: document.getElementById('home'),
        practice: document.getElementById('practice'),
        done: document.getElementById('done'),
        stats: document.getElementById('stats')
    };

    function setGreeting() {
        var hour = new Date().getHours();
        var text = '你好';
        if (hour < 6) text = '夜深了';
        else if (hour < 9) text = '早安';
        else if (hour < 12) text = '上午好';
        else if (hour < 14) text = '午安';
        else if (hour < 18) text = '下午好';
        else text = '晚上好';
        document.getElementById('greeting').textContent = text;
    }

    function formatTime(seconds) {
        var m = Math.floor(seconds / 60);
        var s = seconds % 60;
        return (m < 10 ? '0' : '') + m + ':' + (s < 10 ? '0' : '') + s;
    }

    function showPage(name) {
        Object.keys(pages).forEach(function(key) {
            pages[key].classList.remove('active');
        });
        pages[name].classList.add('active');

        document.querySelectorAll('.nav-tab').forEach(function(tab) {
            tab.classList.remove('active');
            if (tab.dataset.page === name) {
                tab.classList.add('active');
            }
        });

        if (name === 'stats') {
            renderHistory();
        }
    }

    function updateBtnText() {
        var modeText = config.mode === 'guided' ? '引导' : '自主';
        document.getElementById('btnText').textContent = config.duration + '分钟 · ' + modeText;
    }

    document.querySelectorAll('[data-duration]').forEach(function(el) {
        el.addEventListener('click', function() {
            config.duration = parseInt(this.dataset.duration);
            document.querySelectorAll('[data-duration]').forEach(function(e) {
                e.classList.remove('active');
            });
            this.classList.add('active');
            updateBtnText();
        });
    });

    document.querySelectorAll('[data-mode]').forEach(function(el) {
        el.addEventListener('click', function() {
            config.mode = this.dataset.mode;
            document.querySelectorAll('[data-mode]').forEach(function(e) {
                e.classList.remove('active');
            });
            this.classList.add('active');
            updateBtnText();
        });
    });

    document.querySelectorAll('[data-page]').forEach(function(el) {
        el.addEventListener('click', function() {
            showPage(this.dataset.page);
        });
    });

    document.getElementById('startBtn').addEventListener('click', function() {
        timeLeft = config.duration * 60;
        totalTime = timeLeft;
        document.getElementById('timer').textContent = formatTime(timeLeft);
        document.getElementById('guide').style.display = config.mode === 'guided' ? 'block' : 'none';
        document.getElementById('controls').innerHTML = '<button class="btn btn-start" id="beginBtn">开始练习</button>';
        bindBeginBtn();
        showPage('practice');
    });

    function bindBeginBtn() {
        var btn = document.getElementById('beginBtn');
        if (btn) {
            btn.addEventListener('click', beginPractice);
        }
    }

    function beginPractice() {
        startTime = new Date();
        document.getElementById('controls').innerHTML = 
            '<button class="btn btn-pause" id="pauseBtn">暂停</button>' +
            '<button class="btn btn-end" id="endBtn">结束</button>';

        document.getElementById('pauseBtn').addEventListener('click', pausePractice);
        document.getElementById('endBtn').addEventListener('click', endPractice);

        timer = setInterval(function() {
            timeLeft--;
            document.getElementById('timer').textContent = formatTime(timeLeft);

            var progress = ((totalTime - timeLeft) / totalTime) * 100;
            document.getElementById('progressBar').style.width = progress + '%';

            updateStage();

            if (timeLeft <= 0) {
                endPractice();
            }
        }, 1000);
    }

    function pausePractice() {
        clearInterval(timer);
        document.getElementById('controls').innerHTML = 
            '<button class="btn btn-start" id="resumeBtn">继续</button>' +
            '<button class="btn btn-end" id="endBtn">结束</button>';

        document.getElementById('resumeBtn').addEventListener('click', beginPractice);
        document.getElementById('endBtn').addEventListener('click', endPractice);
    }

    function updateStage() {
        var elapsed = totalTime - timeLeft;
        var progress = elapsed / totalTime;
        var stage = '准备开始';
        var guide = '';

        if (progress > 0) {
            if (progress < 0.17) {
                stage = '调身';
                guide = '让身体自然放松，脊柱轻轻挺直';
            } else if (progress < 0.67) {
                stage = '调息';
                guide = '吸气...呼气...保持自然的呼吸节奏';
            } else if (progress < 0.89) {
                stage = '观心';
                guide = '觉察身体的感觉，不评判，只是知道';
            } else {
                stage = '收功';
                guide = '慢慢把觉知带回，准备结束练习';
            }
        }

        document.getElementById('stage').textContent = stage;
        if (config.mode === 'guided') {
            document.getElementById('guide').textContent = guide;
        }
    }

    function endPractice() {
        clearInterval(timer);
        var actual = Math.floor((new Date() - startTime) / 60000);
        if (actual < 1) actual = 1;
        document.getElementById('doneTime').textContent = '实际练习 ' + actual + ' 分钟';
        showPage('done');
    }

    document.getElementById('backBtn').addEventListener('click', function() {
        if (confirm('确定要退出练习吗？')) {
            clearInterval(timer);
            showPage('home');
        }
    });

    document.querySelectorAll('[data-rating]').forEach(function(el) {
        el.addEventListener('click', function() {
            rating = parseInt(this.dataset.rating);
            document.querySelectorAll('[data-rating]').forEach(function(star, i) {
                star.classList.toggle('active', i < rating);
            });
        });
    });

    document.getElementById('saveBtn').addEventListener('click', function() {
        var record = {
            id: Date.now(),
            date: new Date().toISOString(),
            duration: config.duration,
            mode: config.mode,
            rating: rating,
            notes: document.getElementById('noteInput').value
        };

        history.unshift(record);
        localStorage.setItem('zhiguan_history', JSON.stringify(history));

        rating = 0;
        document.getElementById('noteInput').value = '';
        document.querySelectorAll('[data-rating]').forEach(function(s) {
            s.classList.remove('active');
        });

        showPage('stats');
    });

    function renderHistory() {
        var container = document.getElementById('historyList');

        if (history.length === 0) {
            container.innerHTML = '<div style="text-align:center;padding:40px;color:rgba(255,255,255,0.5)">还没有练习记录<br><br>开始你的第一次止观练习吧 🧘</div>';
            return;
        }

        container.innerHTML = history.slice(0, 20).map(function(r) {
            var d = new Date(r.date);
            var stars = '★'.repeat(r.rating) + '☆'.repeat(5 - r.rating);
            return '<div class="history-item">' +
                '<div style="display:flex;justify-content:space-between;align-items:center">' +
                '<div>' +
                '<div style="font-size:18px;margin-bottom:4px">' + r.duration + '分钟止观</div>' +
                '<div style="font-size:12px;color:rgba(255,255,255,0.5)">' + 
                (d.getMonth() + 1) + '月' + d.getDate() + '日 · ' + 
                (r.mode === 'guided' ? '引导' : '自主') + '</div>' +
                '</div>' +
                '<div style="color:#ffc107;font-size:20px">' + stars + '</div>' +
                '</div>' +
                (r.notes ? '<div style="margin-top:10px;font-size:14px;color:rgba(255,255,255,0.7)">' + r.notes + '</div>' : '') +
                '</div>';
        }).join('');
    }

    setGreeting();
    bindBeginBtn();
})();
</script>
</body>
</html>
```

